package main

import (
    "fmt"
    "log"
    "net/http"
    "os"
)

// Noncompliant: Debug features enabled in production
const DEBUG = true

func main() {
    // BAD: Debug mode always enabled
    if DEBUG {
        log.SetFlags(log.LstdFlags | log.Lshortfile)
        log.Println("Debug mode enabled")
    }

    http.HandleFunc("/debug", debugHandler)
    http.ListenAndServe(":8080", nil)
}

func debugHandler(w http.ResponseWriter, r *http.Request) {
    // BAD: Exposing internal state in production
    fmt.Fprintf(w, "Debug Info:\n")
    fmt.Fprintf(w, "Environment Variables: %v\n", os.Environ())
    fmt.Fprintf(w, "Request Headers: %v\n", r.Header)
    // Potentially exposing sensitive information
}

func processRequest(req *Request) error {
    // BAD: Verbose error messages in production
    if err := validateRequest(req); err != nil {
        log.Printf("Validation failed: %v, Request: %+v", err, req)
        return fmt.Errorf("validation error: %v, full request: %+v", err, req)
    }
    return nil
}

