package main

import (
    "fmt"
    "log"
    "net/http"
    "os"
)

// Compliant: Environment-based debug configuration
var DEBUG = os.Getenv("DEBUG") == "true"

func main() {
    // GOOD: Debug mode controlled by environment
    if DEBUG {
        log.SetFlags(log.LstdFlags | log.Lshortfile)
        log.Println("Debug mode enabled")
        // Only register debug endpoints in debug mode
        http.HandleFunc("/debug", debugHandler)
    } else {
        // Production logging configuration
        log.SetFlags(0)
    }

    http.HandleFunc("/health", healthHandler)
    http.ListenAndServe(":8080", nil)
}

func debugHandler(w http.ResponseWriter, r *http.Request) {
    // GOOD: Only available when debug is explicitly enabled
    if !DEBUG {
        http.NotFound(w, r)
        return
    }

    // Provide limited, safe debug information
    fmt.Fprintf(w, "Debug Info:\n")
    fmt.Fprintf(w, "Method: %s\n", r.Method)
    fmt.Fprintf(w, "URL: %s\n", r.URL.Path)
    // Don't expose sensitive data
}

func healthHandler(w http.ResponseWriter, r *http.Request) {
    // GOOD: Production-safe endpoint
    w.WriteHeader(http.StatusOK)
    fmt.Fprintf(w, "OK")
}

func processRequest(req *Request) error {
    // GOOD: Different error handling for debug vs production
    if err := validateRequest(req); err != nil {
        if DEBUG {
            log.Printf("Validation failed: %v, Request ID: %s", err, req.ID)
        } else {
            log.Printf("Validation failed for request %s", req.ID)
        }

        // Return safe error message in production
        return fmt.Errorf("validation error")
    }
    return nil
}
